<template>
  <div class="gallery">
    <div class="gallery-item" v-for="(image, index) in images" :key="index">
      <img :src="image.src" :alt="image.alt" @click="openModal(index)" />
    </div>

    <div v-if="showModal" class="modal" @click="closeModal">
      <img :src="currentImage.src" :alt="currentImage.alt" />
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      images: [
        { src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 1 Description' },
        { src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 2 Description' },
        { src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 3 Description' },
		{ src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 1 Description' },
        { src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 2 Description' },
        { src: require("@/assets/mazatlan-playa.jpg"), alt: 'Image 3 Description' },
      ],
      showModal: false,
      currentImageIndex: null,
    };
  },
  computed: {
    currentImage() {
      return this.images[this.currentImageIndex];
    },
  },
  methods: {
    openModal(index) {
      this.currentImageIndex = index;
      this.showModal = true;
    },
    closeModal() {
      this.showModal = false;
      this.currentImageIndex = null;
    },
  },
};
</script>

